INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a1a10900-0000-4000-8000-000000000000','1on1が「報告会」に堕ちるリーダーに共通する構造はどれか。','部下の話を最後まで聴こうとしている','「進捗を確認しなければならない」と思っている','未来の問いから対話を始めている','アイスブレイクに時間をかけすぎている','B',0),
('a1a10900-0000-4000-8000-000000000000','30分の1on1の前半5分で、リーダーが守るべきことはどれか。','仕事の話を、しない','今月の進捗をまず確認する','半年後の目標を先に決める','部下へのアドバイスを一つ渡す','A',1),
('a1a10900-0000-4000-8000-000000000000','「気づくと自分が8割話している」失敗への修正として本文が挙げる目安はどれか。','話す:聴く=8:2にする','聴く:話す=8:2にする','沈黙を必ず埋める','アドバイスを3回以上する','B',2),
('a1a20900-0000-4000-8000-000000000000','本文が一行で定義するフィードバックの本質はどれか。','相手の人格を正しく評価すること','相手の行動を、評価せずに返すこと','良い点だけを伝えて励ますこと','改善策を具体的に指示すること','B',0),
('a1a20900-0000-4000-8000-000000000000','「君、注意力が足りないんじゃない?」を手渡しに変える鍵はどれか。','主語を「君」から「事実」へ移す','声のトーンを柔らかくする','指摘を翌日まで溜めておく','より強い言葉で言い切る','A',1),
('a1a20900-0000-4000-8000-000000000000','うまく回っているチームで、良い点と直してほしい点を返す比率はおおよそどれか。','一対一','二対一','三対一','五対一','C',2),
('a1a30900-0000-4000-8000-000000000000','本文が一行で定義する委任の本質はどれか。','仕事を全部手放して口を出さないこと','手放す「段階」を設計すること','できる部下にだけ仕事を渡すこと','手順を細かく指示して守らせること','B',0),
('a1a30900-0000-4000-8000-000000000000','委任の四段階のうち、「やり方は任せ、結果だけ報告してもらう」のはどれか。','第一段:指示してやらせる','第二段:相談しながらやる','第三段:任せて報告だけ','第四段:完全に任せる','C',1),
('a1a30900-0000-4000-8000-000000000000','「段を飛ばして、いきなり丸投げする」失敗への修正はどれか。','いまの段を見極めてから、一つ手前から渡す','勢いのあるうちに最上段で渡す','やり方を毎日覗きに行く','結果が違えば取り上げて自分でやる','A',2),
('a1a40900-0000-4000-8000-000000000000','本文が一行で定義する評価面談の本質はどれか。','決まった点数を正確に通知する場','半年の事実について、二人の見方をすり合わせる場','上司が課題を一方的に指摘する場','次の昇給額を交渉する場','B',0),
('a1a40900-0000-4000-8000-000000000000','評価を伝える前に、本人の自己評価を「先に」聞く理由はどれか。','部下が話す時間を長く見せるため','上司の評価と本人の自己評価の「ズレ」が見えるため','点数を告げる手間を省くため','部下に反論させないため','B',1),
('a1a40900-0000-4000-8000-000000000000','「サプライズ評価をする」失敗への修正はどれか。','面談当日に強い言葉で伝える','良い点だけを並べて課題は伏せる','日々のフィードバックを溜めず、期中に伝えておく','評価の根拠を曖昧なまま渡す','C',2),
('a1a50900-0000-4000-8000-000000000000','本文が一行で定義する「難しい会話」の本質はどれか。','相手を裁く場ではなく、問題と相手のあいだに立つ時間','どちらが正しいかを決める対決の場','正論で相手を説得しきる場','上司が結論を告げて終える場','A',0),
('a1a50900-0000-4000-8000-000000000000','「辞めたいんです」と切り出されたとき、本文が勧める最初の対応はどれか。','まず引き止めて考え直させる','引き止めず、まず背景を聞く','すぐ人事に引き継いで席を外す','その場で結論を出させる','B',1),
('a1a50900-0000-4000-8000-000000000000','部下の感情を自分で背負い込む失敗への修正として本文が挙げる考え方はどれか。','共感も解決も引き受けない','共感はするが、解決は引き受けない(課題の分離)','感情を打ち消して励ます','すべて自分の責任として抱える','B',2);
